   641|  const adaptiveTimeoutMs = computeAdaptiveTimeoutMs({ promptChars, maxOutputTokens: input.maxOutputTokens });
   642|  const queueLane = classifyRequestLane({ promptChars, maxOutputTokens: input.maxOutputTokens });
