    92|    steps.push(step('dispatch', true, `taskId=${task.id} routedTo=${agentUsed} risk=${task.risk}`));
    93|
    94|    if (task.assignedAgent === 'cto_orchestrator') {
    95|      blockers.push('CTO orchestrator should not self-assign specialist tasks.');
    96|    }
    97|    if (task.status !== 'running') {
    98|      blockers.push(`Expected task status=running, got ${task.status}.`);
    99|    }
   100|
