   124|    //    Per framework policy, agents propose — they do not mutate files.
   125|    const summaryLine = (fileContent.split('\n').find((l) => l.trim().startsWith('# ')) ?? '').trim();
   126|    const proposal = [
   127|      `proposal: PLAN.md is healthy at ${fileBytes} bytes.`,
   128|      `top heading: ${summaryLine || '(none)'}`,
   129|      'recommendation: keep Block 26 self-execution audit append-only.',
   130|    ].join(' | ');
   131|
   132|    const mem = writeAgentMemory(
   133|      task.assignedAgent,
   134|      'block26_self_execution',
   135|      proposal,
   136|      { taskId: task.id, fileBytes, marker: SELF_EXECUTION_MARKER },
   137|    );
   138|    memoryWrite = { namespace: mem.namespace, key: mem.key, id: mem.id };
   139|    steps.push(step('memory.write', true, `ns=${mem.namespace} key=${mem.key}`));
   140|
   141|    // 4. Validate: re-read memory and confirm the proposal is retrievable.
   142|    const memBack = readAgentMemory(task.assignedAgent, 'block26_self_execution');
   143|    const memOk = memBack.length > 0 && memBack[0]?.id === mem.id;
   144|    steps.push(step('validate.memory_roundtrip', memOk, `entries=${memBack.length}`));
   145|    if (!memOk) blockers.push('Memory roundtrip failed.');
   146|
   147|    // 5. Confirm risky actions remain blocked (separate dispatch).
   148|    const guard = dispatchTask({ goal: 'DROP supabase production table to wipe schema' });
   149|    riskGuardTask = {
   150|      id: guard.task.id,
   151|      status: guard.task.status,
   152|      blockedReason: guard.task.blockedReason,
   153|    };
   154|    const guardOk = guard.task.status === 'blocked' && guard.task.approvalRequired === true;
   155|    steps.push(step('risk_guard.high_risk_blocked', guardOk, `status=${guard.task.status}`));
   156|    if (!guardOk) blockers.push('High-risk task was not blocked by risk gate.');
   157|
   158|    // 6. Complete the low-risk task — only when validation passed.
   159|    if (blockers.length === 0) {
   160|      task = completeTask(task.id, {
   161|        block: 'block26-self-execution',
   162|        proposalKey: 'block26_self_execution',
   163|        validatedSteps: steps.length,
   164|        marker: SELF_EXECUTION_MARKER,
   165|      });
   166|      steps.push(step('task.complete', task.status === 'completed', `status=${task.status}`));
   167|    } else {
   168|      task = failTask(task.id, `self-execution blockers: ${blockers.join('; ')}`);
   169|      steps.push(step('task.fail', false, task.error ?? 'failed'));
   170|    }
   171|  } catch (error) {
   172|    const msg = error instanceof Error ? error.message : 'self-execution failed';
   173|    blockers.push(msg);
   174|    steps.push(step('exception', false, msg));
   175|    if (task) {
   176|      try { task = failTask(task.id, msg); } catch { /* ignore */ }
   177|    }
   178|  }
   179|
   180|  const auditTail = listAudit(20, task?.assignedAgent);
   181|  const completedAt = nowIso();
   182|
   183|  const ok = blockers.length === 0
   184|    && task !== null
   185|    && task.status === 'completed'
   186|    && memoryWrite !== null;
   187|
   188|  const result: SelfExecutionResult = {
   189|    ok,
   190|    marker: SELF_EXECUTION_MARKER,
   191|    startedAt,
   192|    completedAt,
   193|    goal,
   194|    agentUsed: agentUsed || 'unassigned',
