   196|    riskGuardTask,
   197|    steps,
   198|    memoryWrite,
   199|    auditCount: auditTail.length,
   200|    auditTail,
   201|    blockers,
   202|  };
   203|
   204|  lastResult = result;
   205|  return result;
   206|}
